import{_ as o,o as t,c as n,ag as a}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"Terminology","description":"","frontmatter":{},"headers":[],"relativePath":"components/terminology.md","filePath":"components/terminology.md"}'),r={name:"components/terminology.md"};function i(c,e,s,d,l,m){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h1><h2 id="progressive-web-components" tabindex="-1">Progressive Web Components <a class="header-anchor" href="#progressive-web-components" aria-label="Permalink to &quot;Progressive Web Components&quot;">​</a></h2><p>A <em>&quot;Progressive Web Component&quot;</em> is a native Custom Element designed in two layers: a base layer of HTML and CSS that renders immediately, without JavaScript, and an enhancement layer of JavaScript that adds reactivity, event handling, and more advanced templating.</p><p>There are two types of Progressive Web Components:</p><h3 id="_1-composite-components" tabindex="-1">1. Composite Components <a class="header-anchor" href="#_1-composite-components" aria-label="Permalink to &quot;1. Composite Components&quot;">​</a></h3><ul><li>Components that wrap and enhance the HTML composed inside them, including other components. What you would also call <em>“HTML Web Components.”</em></li><li>Provide styling, layout, and behavior around the composed content.</li><li>No <code>render()</code> method. Full SSR support out of the box.</li><li>Examples: <code>stack</code>, <code>table</code>, <code>layout</code>, <code>card</code>, <code>banner</code>, <code>visually-hidden</code>, <code>fieldset</code>.</li></ul><h3 id="_2-primitive-components" tabindex="-1">2. Primitive Components <a class="header-anchor" href="#_2-primitive-components" aria-label="Permalink to &quot;2. Primitive Components&quot;">​</a></h3><ul><li>Self-contained components that own and render their own HTML markup.</li><li>All content is controlled through <code>props</code>, nothing is composed into them except <code>text</code> content.</li><li>Require a <code>render()</code> method returning an <code>html</code> tagged template. Partial SSR support out of the box without <code>@elenajs/ssr</code>.</li><li>Examples: <code>button</code>, <code>input</code>, <code>checkbox</code>, <code>radio</code>, <code>textarea</code>, <code>icon</code>, <code>spinner</code>, <code>switch</code>.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">NOTE</p><p>You may wonder: why are they called <strong>Progressive Web Components</strong> and not <strong>Progressive Custom Elements</strong>? <em>Web Component</em> is the more widely recognized term today, and many of Elena’s concepts align closely with what are now called <a href="https://adactio.com/journal/20618" target="_blank" rel="noreferrer">HTML Web Components</a>.</p></div>',9)])])}const u=o(r,[["render",i]]);export{h as __pageData,u as default};
